--
-- Table structure for table `appointment`
--

DROP TABLE IF EXISTS `appointment`;
CREATE TABLE `appointment` (
  `AppointmentID` varchar(50) NOT NULL default '',
  `PatientID` varchar(50) default NULL,
  `DoctorID` varchar(50) default NULL,
  `AppointmentDate` date default NULL,
  `AppointmentTime` time default NULL,
  `Status` enum('pending','confirmed','completed','cancelled') default NULL,
  PRIMARY KEY  (`AppointmentID`),
  KEY `PatientID` (`PatientID`),
  KEY `DoctorID` (`DoctorID`),
  CONSTRAINT `appointment_ibfk_1` FOREIGN KEY (`PatientID`) REFERENCES `patient` (`PatientID`),
  CONSTRAINT `appointment_ibfk_2` FOREIGN KEY (`DoctorID`) REFERENCES `doctor` (`DoctorID`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

