DROP TABLE IF EXISTS `billingsystem`;
CREATE TABLE `billingsystem` (
  `BillID` varchar(50) NOT NULL,
  `PrescriptionID` varchar(50) default NULL,
  `PatientID` varchar(50) default NULL,
  `ItemType` varchar(20) default NULL,
  `ItemID` varchar(50) default NULL,
  `ItemName` varchar(200) default NULL,
  `Description` text,
  `Qty` int(11) default NULL,
  `UnitPrice` decimal(10,2) default NULL,
  `TotalPrice` decimal(10,2) default NULL,
  `BillDate` date default NULL,
  KEY `PrescriptionID` (`PrescriptionID`),
  KEY `PatientID` (`PatientID`),
  CONSTRAINT `billingsystem_ibfk_1` FOREIGN KEY (`PrescriptionID`) REFERENCES `prescriptions` (`PrescriptionID`),
  CONSTRAINT `billingsystem_ibfk_2` FOREIGN KEY (`PatientID`) REFERENCES `patient` (`PatientID`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

