--
-- Table structure for table `medicalrecords`
--

DROP TABLE IF EXISTS `medicalrecords`;
CREATE TABLE `medicalrecords` (
  `MRecordID` varchar(50) NOT NULL,
  `PatientID` varchar(50) default NULL,
  `DoctorID` varchar(50) default NULL,
  `Diagnosis` text,
  `Treatment` text,
  `Description` text,
  `VisitType` varchar(50) default NULL,
  `DateOfVisit` date default NULL,
  PRIMARY KEY  (`MRecordID`),
  KEY `PatientID` (`PatientID`),
  KEY `DoctorID` (`DoctorID`),
  CONSTRAINT `medicalrecords_ibfk_1` FOREIGN KEY (`PatientID`) REFERENCES `patient` (`PatientID`),
  CONSTRAINT `medicalrecords_ibfk_2` FOREIGN KEY (`DoctorID`) REFERENCES `doctor` (`DoctorID`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

