--
-- Table structure for table `patient`
--

DROP TABLE IF EXISTS `patient`;
CREATE TABLE `patient` (
  `PatientID` varchar(50) NOT NULL default '',
  `UserID` varchar(50) default NULL,
  `FirstName` varchar(100) default NULL,
  `LastName` varchar(100) default NULL,
  `FatherName` varchar(100) default NULL,
  `DOB` date default NULL,
  `Address` varchar(208) default NULL,
  `PhonenNumber` varchar(50) default NULL,
  `Email` varchar(50) default NULL,
  `Gender` varchar(20) default NULL,
  `BloodGroup` varchar(90) default NULL,
  `Photo` longblob,
  PRIMARY KEY  (`PatientID`),
  KEY `UserID` (`UserID`),
  CONSTRAINT `patient_ibfk_1` FOREIGN KEY (`UserID`) REFERENCES `user` (`UserID`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

