--
-- Table structure for table `prescriptions`
--

DROP TABLE IF EXISTS `prescriptions`;
CREATE TABLE `prescriptions` (
  `PrescriptionID` varchar(50) NOT NULL,
  `MRecordID` varchar(50) default NULL,
  `PatientID` varchar(50) default NULL,
  `DoctorID` varchar(50) default NULL,
  `PharmacistID` varchar(50) default NULL,
  `MedicineID` varchar(50) default NULL,
  `MedicineName` varchar(100) default NULL,
  `Dosage` varchar(100) default NULL,
  `Qty` int(10) unsigned default NULL,
  `DatePrescribed` date default NULL,
  `Status` enum('pending','dispensed') default NULL,
  PRIMARY KEY  (`PrescriptionID`),
  KEY `MRecordID` (`MRecordID`),
  KEY `PatientID` (`PatientID`),
  KEY `DoctorID` (`DoctorID`),
  KEY `PharmacistID` (`PharmacistID`),
  KEY `MedicineID` (`MedicineID`),
  CONSTRAINT `prescriptions_ibfk_1` FOREIGN KEY (`MRecordID`) REFERENCES `medicalrecords` (`MRecordID`),
  CONSTRAINT `prescriptions_ibfk_2` FOREIGN KEY (`PatientID`) REFERENCES `patient` (`PatientID`),
  CONSTRAINT `prescriptions_ibfk_3` FOREIGN KEY (`DoctorID`) REFERENCES `doctor` (`DoctorID`),
  CONSTRAINT `prescriptions_ibfk_4` FOREIGN KEY (`PharmacistID`) REFERENCES `pharmacist` (`PharmacistID`),
  CONSTRAINT `prescriptions_ibfk_5` FOREIGN KEY (`MedicineID`) REFERENCES `medicine` (`MedicineID`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

